using System.ComponentModel;
using System.Net.Http.Json;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------
var notebook = new ResearchNotebook();
var webSearcher = new WebSearcher();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearcher.SearchWeb),
    AIFunctionFactory.Create(webSearcher.ReadWebPage),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
    AIFunctionFactory.Create(notebook.ClearNotes),
};

// ---------------------------------------------------------------------------
// Build the agent
// ---------------------------------------------------------------------------
IChatClient chatClient = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When given a topic you MUST:
        1. Search the web for relevant information using the SearchWeb tool.
        2. Read the most promising pages using the ReadWebPage tool.
        3. Take structured notes using the AddNote tool as you learn things.
        4. After you have gathered enough information, review your notes with GetNotes
           and produce a well-organized summary with key findings, supporting details,
           and source URLs.

        Be thorough — perform multiple searches with different queries when needed.
        Always cite your sources.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔍  Research Agent  (AI)         ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic))
        continue;

    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase)
        || topic.Equals("exit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.ClearNotes();

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"\nResearching: {topic}\n");
    Console.ResetColor();

    try
    {
        var session = await agent.CreateSessionAsync();
        var response = await agent.RunAsync(
            $"Please research the following topic and provide a comprehensive summary: {topic}",
            session);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("\n── Research Summary ──────────────────────\n");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\nError: {ex.Message}\n");
        Console.ResetColor();
    }
}

Console.WriteLine("Goodbye!");

