+/// <summary>
+/// Provides web search and page-reading tools for the research agent.
+/// Uses the DuckDuckGo HTML interface as a free search backend.
+/// </summary>
+sealed class WebSearcher
+{
+    private static readonly HttpClient Http = new()
+    {
+        DefaultRequestHeaders =
+        {
+            { "User-Agent", "ResearchAgent/1.0" }
+        },
+        Timeout = TimeSpan.FromSeconds(15)
+    };
+
+    [Description("Search the web for a query and return a list of result titles, URLs, and snippets.")]
+    public async Task<string> SearchWeb(
+        [Description("The search query string")] string query)
+    {
+        Console.ForegroundColor = ConsoleColor.DarkYellow;
+        Console.WriteLine($"  🔎 Searching: {query}");
+        Console.ResetColor();
+
+        try
+        {
+            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
+            var html = await Http.GetStringAsync(url);
+
+            var results = ParseDuckDuckGoResults(html);
+
+            if (results.Count == 0)
+                return "No results found.";
+
+            var sb = new StringBuilder();
+            for (var i = 0; i < results.Count; i++)
+            {
+                var (title, link, snippet) = results[i];
+                sb.AppendLine($"{i + 1}. {title}");
+                sb.AppendLine($"   URL: {link}");
+                sb.AppendLine($"   {snippet}");
+                sb.AppendLine();
+            }
+
+            return sb.ToString();
+        }
+        catch (Exception ex)
+        {
+            return $"Search failed: {ex.Message}";
+        }
+    }
+
+    [Description("Read the text content of a web page given its URL.")]
+    public async Task<string> ReadWebPage(
+        [Description("The full URL of the web page to read")] string url)
+    {
+        Console.ForegroundColor = ConsoleColor.DarkYellow;
+        Console.WriteLine($"  📄 Reading: {url}");
+        Console.ResetColor();
+
+        try
+        {
+            var html = await Http.GetStringAsync(url);
+            var text = StripHtml(html);
+
+            const int maxLength = 6000;
+            if (text.Length > maxLength)
+                text = text[..maxLength] + "\n\n[Content truncated]";
+
+            return string.IsNullOrWhiteSpace(text)
+                ? "Could not extract meaningful text from this page."
+                : text;
+        }
+        catch (Exception ex)
+        {
+            return $"Failed to read page: {ex.Message}";
+        }
+    }
+
+    private static List<(string Title, string Url, string Snippet)> ParseDuckDuckGoResults(string html)
+    {
+        var results = new List<(string, string, string)>();
+
+        // Parse result blocks from DuckDuckGo HTML
+        var searchIndex = 0;
+        while (results.Count < 8)
+        {
+            var linkStart = html.IndexOf("class=\"result__a\"", searchIndex, StringComparison.Ordinal);
+            if (linkStart < 0) break;
+
+            var href = ExtractAttribute(html, linkStart, "href");
+            var title = ExtractInnerText(html, linkStart);
+
+            var snippetStart = html.IndexOf("class=\"result__snippet\"", linkStart, StringComparison.Ordinal);
+            var snippet = snippetStart >= 0 ? ExtractInnerText(html, snippetStart) : "";
+
+            searchIndex = snippetStart >= 0 ? snippetStart + 1 : linkStart + 1;
+
+            if (!string.IsNullOrWhiteSpace(href) && !string.IsNullOrWhiteSpace(title))
+            {
+                // DuckDuckGo wraps URLs in a redirect; extract the actual URL
+                var actualUrl = href.Contains("uddg=")
+                    ? Uri.UnescapeDataString(
+                        href[(href.IndexOf("uddg=", StringComparison.Ordinal) + 5)..].Split('&')[0])
+                    : href;
+
+                results.Add((
+                    System.Net.WebUtility.HtmlDecode(title.Trim()),
+                    actualUrl,
+                    System.Net.WebUtility.HtmlDecode(snippet.Trim())));
+            }
+        }
+
+        return results;
+    }
+
+    private static string ExtractAttribute(string html, int startFrom, string attr)
+    {
+        var attrPattern = attr + "=\"";
+        var idx = html.IndexOf(attrPattern, startFrom, StringComparison.OrdinalIgnoreCase);
+        if (idx < 0) return "";
+        idx += attrPattern.Length;
+        var end = html.IndexOf('"', idx);
+        return end < 0 ? "" : html[idx..end];
+    }
+
+    private static string ExtractInnerText(string html, int startFrom)
+    {
+        var tagEnd = html.IndexOf('>', startFrom);
+        if (tagEnd < 0) return "";
+        tagEnd++;
+
+        var closeTag = html.IndexOf('<', tagEnd);
+        if (closeTag < 0) return "";
+
+        return html[tagEnd..closeTag];
+    }
+
+    private static string StripHtml(string html)
+    {
+        // Remove script and style blocks
+        html = System.Text.RegularExpressions.Regex.Replace(
+            html, @"<(script|style)[^>]*>[\s\S]*?</\1>", "", System.Text.RegularExpressions.RegexOptions.IgnoreCase);
+
+        // Remove tags
+        html = System.Text.RegularExpressions.Regex.Replace(html, @"<[^>]+>", " ");
+
+        // Decode entities
+        html = System.Net.WebUtility.HtmlDecode(html);
+
+        // Collapse whitespace
+        html = System.Text.RegularExpressions.Regex.Replace(html, @"[ \t]+", " ");
+        html = System.Text.RegularExpressions.Regex.Replace(html, @"\n{3,}", "\n\n");
+
+        return html.Trim();
+    }
+}
+
+/// <summary>
+/// Provides a simple note-taking tool for the agent to organize findings.
+/// </summary>
+sealed class ResearchNotebook
+{
+    private readonly List<string> _notes = [];
+
+    [Description("Save a research note. Use this to record important findings, facts, or quotes with their source.")]
+    public string AddNote(
+        [Description("The note content, ideally including the source URL")] string note)
+    {
+        _notes.Add(note);
+        Console.ForegroundColor = ConsoleColor.DarkYellow;
+        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
+        Console.ResetColor();
+        return $"Note #{_notes.Count} saved.";
+    }
+
+    [Description("Retrieve all research notes collected so far.")]
+    public string GetNotes()
+    {
+        if (_notes.Count == 0)
+            return "No notes have been taken yet.";
+
+        var sb = new StringBuilder();
+        for (var i = 0; i < _notes.Count; i++)
+            sb.AppendLine($"Note #{i + 1}: {_notes[i]}");
+
+        return sb.ToString();
+    }
+
+    [Description("Clear all research notes to start fresh.")]
+    public string ClearNotes()
+    {
+        _notes.Clear();
+        return "All notes cleared.";
+    }
